const Auth={sessionKey:"churchAdminSession",usersKey:"churchAdminUsers",isAuthenticated(){const session=localStorage.getItem(this.sessionKey);return session!==null},login(username,password){let users=[];if(typeof AppData!=="undefined"&&AppData.getUsers){try{users=AppData.getUsers();if(!users||users.length===0){users=[{id:"1",name:"Administrator",username:"admin",password:"admin123",role:"admin",status:"active"}];localStorage.setItem(this.usersKey,JSON.stringify(users))}}catch(e){console.warn("AppData not ready, using fallback");users=JSON.parse(localStorage.getItem(this.usersKey)||"[]")}}else{users=JSON.parse(localStorage.getItem(this.usersKey)||"[]")}if(!users||users.length===0){users=[{id:"1",name:"Administrator",username:"admin",password:"admin123",role:"admin",status:"active"}];localStorage.setItem(this.usersKey,JSON.stringify(users));if(typeof AppData!=="undefined"&&AppData.addUser){try{AppData.addUser(users[0])}catch(e){console.warn("Could not add user to AppData")}}}const user=users.find(u=>u.username===username&&u.password===password&&u.status==="active");if(!user){return false}localStorage.setItem(this.sessionKey,JSON.stringify({userId:user.id,loginAt:(new Date).toISOString()}));return true},logout(){localStorage.removeItem(this.sessionKey);window.location.reload()},isAdmin(){const session=localStorage.getItem(this.sessionKey);if(!session)return false;const user=this.getCurrentUser();return user&&user.role==="admin"},isAdminSync(){return this.isAdmin()},getCurrentUserSync(){return this.getCurrentUser()},canDelete(){return this.isAdmin()},canDeleteSync(){return this.isAdminSync()},getCurrentUser(){const session=localStorage.getItem(this.sessionKey);if(!session)return null;if(typeof AppData!=="undefined"&&AppData.getData&&AppData.getUsers){try{const data=AppData.getData();if(data&&data.users&&Array.isArray(data.users)){const users=data.users;const userId=JSON.parse(session).userId;const user=users.find(u=>u.id===userId);if(user)return user}}catch(e){console.warn("Error reading from AppData:",e)}}const users=JSON.parse(localStorage.getItem(this.usersKey)||"[]");const userId=JSON.parse(session).userId;return users.find(u=>u.id===userId)||null},async requireAuth(){if(this.isAuthenticated()){document.body.classList.remove("auth-screen");return true}this.renderLogin();return false},renderLogin(errorMessage=""){document.body.classList.add("auth-screen");const content=document.getElementById("content");if(!content)return;content.innerHTML=`\n            <div class="auth-card">\n                <div style="text-align:center; margin-bottom: 20px;">\n                    <h2 style="margin-bottom:6px;">Login Admin Gereja</h2>\n                    <p style="margin:0; color: var(--text-secondary);">Silakan masuk untuk melanjutkan</p>\n                </div>\n                ${errorMessage?`<div style="background: rgba(229,62,62,0.1); color: var(--danger); border:1px solid rgba(229,62,62,0.2); border-radius: 8px; padding: 10px; margin-bottom: 12px;">${errorMessage}</div>`:""}\n                <form id="loginForm">\n                    <div class="form-group">\n                        <label class="form-label required">Username</label>\n                        <input type="text" class="form-input" name="username" required autofocus>\n                    </div>\n                    <div class="form-group">\n                        <label class="form-label required">Password</label>\n                        <input type="password" class="form-input" name="password" required>\n                    </div>\n                    <button type="submit" class="btn btn-primary" style="width:100%; justify-content:center;">Masuk</button>\n                </form>\n                <p style="margin-top: 12px; color: var(--text-muted); font-size: 0.85rem; text-align:center;">\n                    Default: <strong>admin</strong> / <strong>admin123</strong>\n                </p>\n            </div>\n        `;const form=document.getElementById("loginForm");if(form){form.addEventListener("submit",async event=>{event.preventDefault();const formData=Object.fromEntries(new FormData(form).entries());const ok=this.login(formData.username?.trim(),formData.password||"");if(!ok){this.renderLogin("Username atau password salah.");return}window.location.reload()})}}};